sql:
SELECT powder_type
FROM powders
WHERE sintered_density_pct > 90;

SELECT COUNT(*) AS supplier_count
FROM powders
WHERE supplier = 'Supplier A';

external_knowledge:
- Assuming 'detailed summary' refers to combining all available information related to each powder type; 
- 'powder types' are categorized based on their properties and parameters for easier identification and management; 
- The context of 'D50 particle size' and other technical terms is understood within the domain of materials science and powder technology.

- High morphology in materials science generally refers to a desirable structure or shape of particles that can lead to better performance in the final product; 
- Heating rate in materials processing refers to how fast the material is heated, which can significantly affect the final properties of the material; 
- Sintering temperature is a critical parameter in materials processing that determines the temperature at which material powders are compacted into a solid form; 
- D50 particle size is a measure of the median particle size in a powder, indicating the size below which 50% of the particles fall.

sql:
SELECT powder_type
  FROM powders
  WHERE sintering_temp_c = (SELECT MAX(sintering_temp_c) FROM powders);

SELECT powder_type 
FROM powders 
WHERE powder_id = 0;

SELECT powder_id 
FROM powders 
ORDER BY powder_id ASC;

